	uint8_t rb_start;
	uint8_t snr[NFAPI_NUM_RB_MAX];
} nfapi_srs_indication_fdd_rel8_t;
```

And `NFAPI_NUM_RB_MAX` is defined as 1000.

The `pullarray8` function is:
```c
uint32_t pullarray8(uint8_t **in, uint8_t out[], uint32_t max_len, uint32_t len, uint8_t *end) {
  if(len == 0)
    return 1;

  if(len > max_len) {
    NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s exceed array size (%d > %d)\n", __FUNCTION__, len, max_len);
    on_error();
    return 0;
  }

  if((end - (*in)) >= sizeof(uint8_t) * len) {
    memcpy(out, (*in), len);
    (*in)+=len;
    return sizeof(uint8_t) * len;
  } else {
    NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s no space in buffer\n", __FUNCTION__);
    on_error();
    return 0;
  }
}
```

So the `pullarray8` function does check if `len > max_len` and calls `on_error()` if it does. However, the issue mentioned in the PR is about "string buffer overrun from unbounded string copy or concatenation". 

